import { z } from "zod";

export const RagUploadSchema = z.object({
  // The corpus group this document belongs to
  groupId: z.string().uuid("Invalid Group ID format"),
  
  // Optional name from the user, otherwise generated by the server
  docName: z.string().optional(),
  
  // The optional raw inputs for the extraction service (if not uploading a file)
  url: z.string().url("Invalid URL format").optional(),
  text: z.string().min(1, "Text content cannot be empty").optional(),
});
